    def maximumSubarraySum(self, nums: List[int], k: int) -> int:
        min_prefix = {}
        running_sum = 0
        max_sum = float('-inf')

        for num in nums:
            # Check for good subarray ending at current num
            # We need nums[i] such that |nums[i] - num| == k
            # So nums[i] == num + k or nums[i] == num - k
            target1 = num + k
            target2 = num - k

            if target1 in min_prefix:
                max_sum = max(max_sum, running_sum + num - min_prefix[target1])
            if target2 in min_prefix:
                max_sum = max(max_sum, running_sum + num - min_prefix[target2])

            # Update min_prefix for current num
            # We want to store the minimum prefix sum before the current num
            # This allows us to maximize the subarray sum for future occurrences
            if num not in min_prefix:
                min_prefix[num] = running_sum
            else:
                min_prefix[num] = min(min_prefix[num], running_sum)

            running_sum += num

        return max_sum if max_sum != float('-inf') else 0
