class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Convert all numbers in arr1 to strings and store all their prefixes in a set.
        # This allows O(1) average time complexity for prefix lookups.
        prefixes = set()
        for num in arr1:
            s = str(num)
            # Generate all prefixes of the string representation
            # e.g., for "123", prefixes are "1", "12", "123"
            for i in range(1, len(s) + 1):
                prefixes.add(s[:i])

        max_len = 0

        # For each number in arr2, check its prefixes against the set.
        # We want the longest common prefix, so we check from longest to shortest.
        for num in arr2:
            s = str(num)
            # Check prefixes from longest to shortest
            for i in range(len(s), 0, -1):
                if s[:i] in prefixes:
                    if i > max_len:
                        max_len = i
                    # Since we are checking from longest, the first match is the longest for this number.
                    break

        return max_len
